var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No. CSM002M000537-49: <color=#ffd34c>에블린 워커</color>","JPN":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No. CSM002M000537-49: <color=#ffd34c>イーヴリンウォーカー</color>","ENG":"(ENG)NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No. CSM002M000537-49: <color=#ffd34c>에블린 워커</color>","TWN":"(TWN)NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No. CSM002M000537-49: <color=#ffd34c>에블린 워커</color>"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"안녕하십니까, ████ 대행. 관찰대상 문제로 연락드렸습니다.","JPN":"元気ですか、████代行。観察対象問題でご連絡致しました。","ENG":"(ENG)안녕하십니까, ████ 대행. 관찰대상 문제로 연락드렸습니다.","TWN":"(TWN)안녕하십니까, ████ 대행. 관찰대상 문제로 연락드렸습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"문제야 언제나 터지는 법이지.\\n이번엔 누군가?","JPN":"問題だけはいつも起こるものである。\\n今回は誰か?","ENG":"(ENG)문제야 언제나 터지는 법이지.\\n이번엔 누군가?","TWN":"(TWN)문제야 언제나 터지는 법이지.\\n이번엔 누군가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"새디어스 모건, 만 57세.\\n신장 186.6cm. 체중 89kg 추정.","JPN":"タデウス・モーガン、満57歳。\\n身長186.6cm.体重89kg推定。","ENG":"(ENG)새디어스 모건, 만 57세.\\n신장 186.6cm. 체중 89kg 추정.","TWN":"(TWN)새디어스 모건, 만 57세.\\n신장 186.6cm. 체중 89kg 추정."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"스코틀랜드 출신으로, 프리드웬 기관의 일원입니다.","JPN":"スコットランド出身で、プリドウェン機関の一員です。","ENG":"(ENG)스코틀랜드 출신으로, 프리드웬 기관의 일원입니다.","TWN":"(TWN)스코틀랜드 출신으로, 프리드웬 기관의 일원입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"현 관리국 기준 등급은 B급으로, 열흘 전 프리드웬과 제 3종 침식체 간의 교전에서 재목격됐습니다.","JPN":"現管理局基準等級はB級で、十日前プリドウェンと第3種侵食体間の交戦で材木格されました。","ENG":"(ENG)현 관리국 기준 등급은 B급으로, 열흘 전 프리드웬과 제 3종 침식체 간의 교전에서 재목격됐습니다.","TWN":"(TWN)현 관리국 기준 등급은 B급으로, 열흘 전 프리드웬과 제 3종 침식체 간의 교전에서 재목격됐습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"재목격?","JPN":"材木格?","ENG":"(ENG)재목격?","TWN":"(TWN)재목격?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 기존 자료에서는 대환류 당시 사망한 것으로 등재되어 있더군요.","JPN":"はい。既存資料では大患類当時死亡したことで登録されていますね。","ENG":"(ENG)네. 기존 자료에서는 대환류 당시 사망한 것으로 등재되어 있더군요.","TWN":"(TWN)네. 기존 자료에서는 대환류 당시 사망한 것으로 등재되어 있더군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"이래서야 요원들에게 데이터베이스를 참고하라고 지시하기도 어렵습니다.","JPN":"以来で要員にデータベースを参考しなさいと指示するにも難しいです。","ENG":"(ENG)이래서야 요원들에게 데이터베이스를 참고하라고 지시하기도 어렵습니다.","TWN":"(TWN)이래서야 요원들에게 데이터베이스를 참고하라고 지시하기도 어렵습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"대환류 이후라면 어쩔 수 없지. 기존에 등재된 인원들만 일정 기간을 두고 자동 갱신되었으니까.","JPN":"大患類以後なら仕方ないでしょう。既存に登録された人員だけ一定期間を置いて自動更新されたから。","ENG":"(ENG)대환류 이후라면 어쩔 수 없지. 기존에 등재된 인원들만 일정 기간을 두고 자동 갱신되었으니까.","TWN":"(TWN)대환류 이후라면 어쩔 수 없지. 기존에 등재된 인원들만 일정 기간을 두고 자동 갱신되었으니까."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"당시 사망 상태로 변경됐다면 특별한 사건 없이는 그대로 남아 있었을 걸세.","JPN":"当時死亡状態で変更されたら特別な事件なしにはそのまま残っていたかけにしよう。","ENG":"(ENG)당시 사망 상태로 변경됐다면 특별한 사건 없이는 그대로 남아 있었을 걸세.","TWN":"(TWN)당시 사망 상태로 변경됐다면 특별한 사건 없이는 그대로 남아 있었을 걸세."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그렇다면 대환류 이후로 단 한 번도 전면에 모습을 드러내지 않았단 뜻이군요.","JPN":"それならば大患類以後でただ一回も全面に姿を現わさなかったという意味ですね。","ENG":"(ENG)그렇다면 대환류 이후로 단 한 번도 전면에 모습을 드러내지 않았단 뜻이군요.","TWN":"(TWN)그렇다면 대환류 이후로 단 한 번도 전면에 모습을 드러내지 않았단 뜻이군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그런 셈이지. 아마 조직 개편 덕분에 수면 위로 나온 모양이군.","JPN":"そんなつもりなの。多分組織改編のおかげで睡眠上で出たようであるね。","ENG":"(ENG)그런 셈이지. 아마 조직 개편 덕분에 수면 위로 나온 모양이군.","TWN":"(TWN)그런 셈이지. 아마 조직 개편 덕분에 수면 위로 나온 모양이군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"정보과가 그간의 행적을 추적 중입니다.\\n불미스러운 일이 일어나지 않도록 주의하겠습니다.","JPN":"情報科がその間の行跡を追跡中です。\\nよくない事が起きないように注意します。","ENG":"(ENG)정보과가 그간의 행적을 추적 중입니다.\\n불미스러운 일이 일어나지 않도록 주의하겠습니다.","TWN":"(TWN)정보과가 그간의 행적을 추적 중입니다.\\n불미스러운 일이 일어나지 않도록 주의하겠습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"나야 괜찮네. 기다리는 게 내 일이지.\\n관찰대상에 등재하고 조사를 속행하게.","JPN":"私だけは大丈夫であるね。待つのが私の事だ。\\n観察対象に登録して調査を続行しなさい。","ENG":"(ENG)나야 괜찮네. 기다리는 게 내 일이지.\\n관찰대상에 등재하고 조사를 속행하게.","TWN":"(TWN)나야 괜찮네. 기다리는 게 내 일이지.\\n관찰대상에 등재하고 조사를 속행하게."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 1차 조사 결과는 데이터베이스로 전송해 드리겠습니다.\\n평가하시는 데 소소하게나마 도움이 될 겁니다.","JPN":"はい。１次調査結果はデータベースに転送して差し上げます。\\n評価するのにこまごましいがそれでも役に立つでしょう。","ENG":"(ENG)네. 1차 조사 결과는 데이터베이스로 전송해 드리겠습니다.\\n평가하시는 데 소소하게나마 도움이 될 겁니다.","TWN":"(TWN)네. 1차 조사 결과는 데이터베이스로 전송해 드리겠습니다.\\n평가하시는 데 소소하게나마 도움이 될 겁니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};